models.ts:
interface PaymentRegistrationRequest {
  idempotency_key: string;
  amount: number;
  currency: string;
  return_url: string;
  payment_order_id: string;
  seller_id: string;
}

interface PaymentRegistrationResponse {
  token: string;
  currency: string;
  amount: number;
  payment_order_id: string;
  seller_id: string;
}

// id => snowflake id; primary key; set when Account added to database
// currency => max length of 3 characters
// unique constraint on (owner_id, name)
interface Account {
  id: number;
  name: "cash" | "escrow" | "income" | null; // relevant to platform
  type: "income" | "asset" | "liability";
  owner_id: string; // can be a seller_id, 'platform', a psp (eg 'stripe'), or a payout service (eg 'tipalti')
  currency: string;
}

// id => snowflake id; primary key; set when Transaction added to database
// payment_order_id => add an index
// created_at => datetime; the time when Transaction is created
// unique constraint on (payment_order_id, step)
interface Transaction {
  id: number;
  payment_order_id: string;
  step:
    | "step1_payin"
    | "step2a_payin-complete"
    | "step2b_fufilled"
    | "refund"
    | "step3_payout"
    | "step4_payout-received";
  created_at: string;
}

// id => snowflake id; primary key; set when LedgerEntry added to database
// transaction => foreign key field to Transaction.id
// account => foreign key field to Account.id
// amount => integer only
// currency => max length of 3 characters
// created_at => datetime; the time when Transaction is created
interface LedgerEntry {
  id: number;
  transaction: Transaction;
  account: Account;
  direction: "debit" | "credit";
  amount: number;
  currency: string;
  created_at: string;
}

// id => primary key
// price => integer
// currency => max length of 3
interface Item {
  id: string;
  seller_id: string;
  price: number;
  currency: string;
}

// id => primary key
interface Order {
  id: string;
}

// many to many between Orders and Items
interface OrderItem {
  item: Item;
  order: Order;
}

// id => primary key; composite of order.id and attempt_idx
// unique on (order, attempt_idx)
// order => foreign key to Order; put index on column
// seller_id => set from the seller_id of the Items belonging to the Order (assumed uniform across the order's items)
// amount => integer; the amount registered with the PSP (sum of the order's Item prices), same value sent in PaymentRegistrationRequest
// currency => max length of 3 characters; from the order's Items (uniform), same value sent in PaymentRegistrationRequest
// created_at => set at first insertion time
interface OrderPayment {
  id: string;
  order: Order;
  seller_id: string;
  amount: number;
  currency: string;
  attempt_idx: number;
  created_at: string;
  status:
    | "pending"
    | "register_success"
    | "register_fail"
    | "payment_success"
    | "payment_fail";
  token?: string;
}

interface OrderCheckoutResponse {
  token?: string;
  status: string;
}

interface MakePaymentRequest {
  token: string;
  card_number: string;
}

interface PaymentWebhookRequest {
  status: "success" | "fail";
  currency: string;
  amount: number;
  payment_order_id: string;
  seller_id: string;
}

// id => snowflake id; primary key; set when Refund added to database
// created_at => datetime; the time when refund is created
interface Refund {
  id: number;
  payment_order_id: string;
  created_at: string;
}

// id => snowflake id; primary key; set when Payout added to database
interface Payout {
  id: number;
  payment_order_id: string;
  created_at: string;
}

// id => snowflake id; primary key
// payment_order_id => add an index
interface PayoutReadiness {
  id: number;
  payment_order_id: string;
  payin_complete: boolean;
  fufilled: boolean;
  created_at: string;
}

interface MakePayoutRequest {
  idempotency_key: string;
  amount: number;
  currency: string;
  recipient: string;
}
